import re
from typing import List

def detect_chunk_truncation(retrieved_chunks: List[str]) -> List[dict]:
    truncation_issues = []
    truncation_patterns = [r'\n\s*$', r'\.\s*$', r'[,;]\s*$']

    for i, chunk in enumerate(retrieved_chunks):
        is_truncated = any(re.search(pattern, chunk.strip()) for pattern in truncation_patterns)
        char_count = len(chunk)

        if is_truncated or char_count < 50:
            truncation_issues.append({
                'chunk_index': i,
                'is_truncated': is_truncated,
                'length': char_count,
                'content_preview': chunk[:100] + '...'
            })

    return truncation_issues
